seedUsers();

// GraphQL Schema
const typeDefs = gql`
  enum Role {
    ADMIN
    MODERATOR
    USER
  }

  enum SortField {
    USERNAME
    EMAIL
    FIRST_NAME
    LAST_NAME
    CREATED_AT
    UPDATED_AT
  }

  enum SortOrder {
    ASC
    DESC
  }

  type User {
    id: ID!
    username: String!
    email: String!
    firstName: String!
    lastName: String!
    fullName: String!
    role: Role!
    isActive: Boolean!
    createdAt: String!
    updatedAt: String!
  }

  type UserBatchResult {
    found: [User!]!
    notFoundIds: [ID!]!
    totalRequested: Int!
    totalFound: Int!
  }

  type UsersPage {
    users: [User!]!
    totalCount: Int!
    page: Int!
    pageSize: Int!
    totalPages: Int!
    hasNextPage: Boolean!
    hasPreviousPage: Boolean!
  }

  type BulkOperationResult {
    successCount: Int!
    failureCount: Int!
    successIds: [ID!]!
    failedIds: [ID!]!
    errors: [BulkError!]!
  }

  type BulkError {
    id: ID!
    message: String!
  }

  input UserFilter {
    roles: [Role!]
    isActive: Boolean
    searchTerm: String
    emails: [String!]
    usernames: [String!]
  }

  input SortInput {
    field: SortField!
    order: SortOrder!
  }

  input CreateUserInput {
    username: String!
    email: String!
    firstName: String!
    lastName: String!
    role: Role
  }

  input UpdateUserInput {
    username: String
    email: String
    firstName: String
    lastName: String
    role: Role
    isActive: Boolean
  }

  input BulkUpdateInput {
    id: ID!
    data: UpdateUserInput!
  }

  type Query {
    # Single user fetch
    user(id: ID!): User

    # Bulk fetch by array of IDs - reduces round trips for dashboard
    users(ids: [ID!]!): UserBatchResult!

    # Fetch users by array of emails
    usersByEmails(emails: [String!]!): UserBatchResult!

    # Fetch users by array of usernames
    usersByUsernames(usernames: [String!]!): UserBatchResult!

    # Paginated and filtered user list for dashboard tables
    usersList(
      page: Int
      pageSize: Int
      filter: UserFilter
      sort: SortInput
    ): UsersPage!

    # Fetch users by roles (array-based)
    usersByRoles(roles: [Role!]!): [User!]!

    # Dashboard stats
    dashboardStats: DashboardStats!
  }

  type DashboardStats {
    totalUsers: Int!
    activeUsers: Int!
    inactiveUsers: Int!
    usersByRole: [RoleCount!]!
  }

  type RoleCount {
    role: Role!
    count: Int!
  }

  type Mutation {
    # Single user operations
    createUser(input: CreateUserInput!): User!
    updateUser(id: ID!, input: UpdateUserInput!): User
    deleteUser(id: ID!): Boolean!

    # Bulk operations - array-based for efficiency
    bulkCreateUsers(inputs: [CreateUserInput!]!): [User!]!
    bulkUpdateUsers(inputs: [BulkUpdateInput!]!): BulkOperationResult!
    bulkDeleteUsers(ids: [ID!]!): BulkOperationResult!
    bulkActivateUsers(ids: [ID!]!): BulkOperationResult!
    bulkDeactivateUsers(ids: [ID!]!): BulkOperationResult!
    bulkChangeRole(ids: [ID!]!, role: Role!): BulkOperationResult!
  }
`;

// Resolvers
const resolvers = {
  User: {
    fullName: (parent) => `${parent.firstName} ${parent.lastName}`,
  },

  Query: {
    user: (_, { id }) => {
      return users.get(id) || null;
    },

    // Array-based query: users(ids: [1,2,3,4,5...100])
    users: (_, { ids }) => {
      const found = [];
      const notFoundIds = [];

      ids.forEach(id => {
        const user = users.get(id);
        if (user) {
          found.push(user);
        } else {
          notFoundIds.push(id);
        }
      });

      return {
        found,
        notFoundIds,
        totalRequested: ids.length,
        totalFound: found.length,
      };
    },

    // Array-based query by emails
    usersByEmails: (_, { emails }) => {
      const allUsers = Array.from(users.values());
      const emailSet = new Set(emails.map(e => e.toLowerCase()));
      const found = allUsers.filter(u => emailSet.has(u.email.toLowerCase()));
      const foundEmails = new Set(found.map(u => u.email.toLowerCase()));
      const notFoundIds = emails.filter(e => !foundEmails.has(e.toLowerCase()));

      return {
        found,
        notFoundIds,
        totalRequested: emails.length,
        totalFound: found.length,
      };
    },

    // Array-based query by usernames
    usersByUsernames: (_, { usernames }) => {
      const allUsers = Array.from(users.values());
      const usernameSet = new Set(usernames.map(u => u.toLowerCase()));
      const found = allUsers.filter(u => usernameSet.has(u.username.toLowerCase()));
      const foundUsernames = new Set(found.map(u => u.username.toLowerCase()));
      const notFoundIds = usernames.filter(u => !foundUsernames.has(u.toLowerCase()));

      return {
        found,
        notFoundIds,
        totalRequested: usernames.length,
        totalFound: found.length,
      };
    },

    // Paginated list with filtering and sorting
    usersList: (_, { page = 1, pageSize = 10, filter, sort }) => {
      let allUsers = Array.from(users.values());

      // Apply filters
      if (filter) {
        if (filter.roles && filter.roles.length > 0) {
          const roleSet = new Set(filter.roles);
          allUsers = allUsers.filter(u => roleSet.has(u.role));
        }

        if (filter.isActive !== undefined && filter.isActive !== null) {
          allUsers = allUsers.filter(u => u.isActive === filter.isActive);
        }

        if (filter.searchTerm) {
          const term = filter.searchTerm.toLowerCase();
          allUsers = allUsers.filter(u =>
            u.username.toLowerCase().includes(term) ||
            u.email.toLowerCase().includes(term) ||
            u.firstName.toLowerCase().includes(term) ||
            u.lastName.toLowerCase().includes(term)
          );
        }

        if (filter.emails && filter.emails.length > 0) {
          const emailSet = new Set(filter.emails.map(e => e.toLowerCase()));
          allUsers = allUsers.filter(u => emailSet.has(u.email.toLowerCase()));
        }

        if (filter.usernames && filter.usernames.length > 0) {
          const usernameSet = new Set(filter.usernames.map(u => u.toLowerCase()));
          allUsers = allUsers.filter(u => usernameSet.has(u.username.toLowerCase()));
        }
      }

      // Apply sorting
      if (sort) {
        const fieldMap = {
          USERNAME: 'username',
          EMAIL: 'email',
          FIRST_NAME: 'firstName',
          LAST_NAME: 'lastName',
          CREATED_AT: 'createdAt',
          UPDATED_AT: 'updatedAt',
        };

        const field = fieldMap[sort.field];
        const multiplier = sort.order === 'ASC' ? 1 : -1;

        allUsers.sort((a, b) => {
          const aVal = a[field] || '';
          const bVal = b[field] || '';
          return multiplier * aVal.localeCompare(bVal);
        });
      }

      const totalCount = allUsers.length;
      const totalPages = Math.ceil(totalCount / pageSize);
      const start = (page - 1) * pageSize;
      const paginatedUsers = allUsers.slice(start, start + pageSize);

      return {
        users: paginatedUsers,
        totalCount,
        page,
        pageSize,
        totalPages,
        hasNextPage: page < totalPages,
        hasPreviousPage: page > 1,
      };
    },

    // Array-based role query
    usersByRoles: (_, { roles }) => {
      const roleSet = new Set(roles);
      return Array.from(users.values()).filter(u => roleSet.has(u.role));
    },

    dashboardStats: () => {
      const allUsers = Array.from(users.values());
      const roleCountMap = {};

      allUsers.forEach(u => {
        roleCountMap[u.role] = (roleCountMap[u.role] || 0) + 1;
      });

      return {
        totalUsers: allUsers.length,
        activeUsers: allUsers.filter(u => u.isActive).length,
        inactiveUsers: allUsers.filter(u => !u.isActive).length,
        usersByRole: Object.entries(roleCountMap).map(([role, count]) => ({ role, count })),
      };
    },
  },

  Mutation: {
    createUser: (_, { input }) => {
      // Check for duplicate username/email
      const allUsers = Array.from(users.values());
      if (allUsers.some(u => u.username.toLowerCase() === input.username.toLowerCase())) {
        throw new Error(`Username "${input.username}" already exists`);
      }
      if (allUsers.some(u => u.email.toLowerCase() === input.email.toLowerCase())) {
        throw new Error(`Email "${input.email}" already exists`);
      }

      const now = new Date().toISOString();
      const user = {
        id: uuidv4(),
        username: input.username,
        email: input.email,
        firstName: input.firstName,
        lastName: input.lastName,
        role: input.role || 'USER',
        isActive: true,
        createdAt: now,
        updatedAt: now,
      };

      users.set(user.id, user);
      return user;
    },

    updateUser: (_, { id, input }) => {
      const user = users.get(id);
      if (!user) return null;

      const allUsers = Array.from(users.values());

      if (input.username && input.username.toLowerCase() !== user.username.toLowerCase()) {
        if (allUsers.some(u => u.id !== id && u.username.toLowerCase() === input.username.toLowerCase())) {
          throw new Error(`Username "${input.username}" already exists`);
        }
      }

      if (input.email && input.email.toLowerCase() !== user.email.toLowerCase()) {
        if (allUsers.some(u => u.id !== id && u.email.toLowerCase() === input.email.toLowerCase())) {
          throw new Error(`Email "${input.email}" already exists`);
        }
      }

      const updatedUser = {
        ...user,
        ...Object.fromEntries(Object.entries(input).filter(([_, v]) => v !== undefined && v !== null)),
        updatedAt: new Date().toISOString(),
      };

      users.set(id, updatedUser);
      return updatedUser;
    },

    deleteUser: (_, { id }) => {
      if (!users.has(id)) return false;
      users.delete(id);
      return true;
    },

    // Bulk create - array-based
    bulkCreateUsers: (_, { inputs }) => {
      const allUsers = Array.from(users.values());
      const existingUsernames = new Set(allUsers.map(u => u.username.toLowerCase()));
      const existingEmails = new Set(allUsers.map(u => u.email.toLowerCase()));
      const createdUsers = [];
      const now = new Date().toISOString();

      for (const input of inputs) {
        if (existingUsernames.has(input.username.toLowerCase())) {
          throw new Error(`Username "${input.username}" already exists`);
        }
        if (existingEmails.has(input.email.toLowerCase())) {
          throw new Error(`Email "${input.email}" already exists`);
        }

        const user = {
          id: uuidv4(),
          username: input.username,
          email: input.email,
          firstName: input.firstName,
          lastName: input.lastName,
          role: input.role || 'USER',
          isActive: true,
          createdAt: now,
          updatedAt: now,
        };

        users.set(user.id, user);
        existingUsernames.add(input.username.toLowerCase());
        existingEmails.add(input.email.toLowerCase());
        createdUsers.push(user);
      }

      return createdUsers;
    },

    // Bulk update - array-based
    bulkUpdateUsers: (_, { inputs }) => {
      const successIds = [];
      const failedIds = [];
      const errors = [];

      for (const { id, data } of inputs) {
        const user = users.get(id);
        if (!user) {
          failedIds.push(id);
          errors.push({ id, message: `User with id "${id}" not found` });
          continue;
        }

        try {
          const updatedUser = {
            ...user,
            ...Object.fromEntries(Object.entries(data).filter(([_, v]) => v !== undefined && v !== null)),
            updatedAt: new Date().toISOString(),
          };
          users.set(id, updatedUser);
          successIds.push(id);
        } catch (err) {
          failedIds.push(id);
          errors.push({ id, message: err.message });
        }
      }

      return {
        successCount: successIds.length,
        failureCount: failedIds.length,
        successIds,
        failedIds,
        errors,
      };
    },

    // Bulk delete - array-based: bulkDeleteUsers(ids: [1,2,3,4,5])
    bulkDeleteUsers: (_, { ids }) => {
      const successIds = [];
      const failedIds = [];
      const errors = [];

      ids.forEach(id => {
        if (users.has(id)) {
          users.delete(id);
          successIds.push(id);
        } else {
          failedIds.push(id);
          errors.push({ id, message: `User with id "${id}" not found` });
        }
      });

      return {
        successCount: successIds.length,
        failureCount: failedIds.length,
        successIds,
        failedIds,
        errors,
      };
    },

    // Bulk activate - array-based
    bulkActivateUsers: (_, { ids }) => {
      const successIds = [];
      const failedIds = [];
      const errors = [];

      ids.forEach(id => {
        const user = users.get(id);
        if (user) {
          user.isActive = true;
          user.updatedAt = new Date().toISOString();
          users.set(id, user);
          successIds.push(id);
        } else {
          failedIds.push(id);
          errors.push({ id, message: `User with id "${id}" not found` });
        }
      });

      return {
        successCount: successIds.length,
        failureCount: failedIds.length,
        successIds,
        failedIds,
        errors,
      };
    },

    // Bulk deactivate - array-based
    bulkDeactivateUsers: (_, { ids }) => {
      const successIds = [];
      const failedIds = [];
      const errors = [];

      ids.forEach(id => {
        const user = users.get(id);
        if (user) {
          user.isActive = false;
          user.updatedAt = new Date().toISOString();
          users.set(id, user);
          successIds.push(id);
        } else {
          failedIds.push(id);
          errors.push({ id, message: `User with id "${id}" not found` });
        }
      });

      return {
        successCount: successIds.length,
        failureCount: failedIds.length,
        successIds,
        failedIds,
        errors,
      };
    },

    // Bulk role change - array-based
    bulkChangeRole: (_, { ids, role }) => {
      const successIds = [];
      const failedIds = [];
      const errors = [];

      ids.forEach(id => {
        const user = users.get(id);
        if (user) {
          user.role = role;
          user.updatedAt = new Date().toISOString();
          users.set(id, user);
          successIds.push(id);
        } else {
          failedIds.push(id);
          errors.push({ id, message: `User with id "${id}" not found` });
        }
      });

      return {
        successCount: successIds.length,
        failureCount: failedIds.length,
        successIds,
        failedIds,
        errors,
      };
    },
  },
};

// Create and start the Apollo Server
const server = new ApolloServer({
  typeDefs,
  resolvers,
  introspection: true,
  formatError: (error) => {
    console.error('GraphQL Error:', error);
    return {
      message: error.message,
      path: error.path,
      extensions: {
        code: error.extensions?.code || 'INTERNAL_SERVER_ERROR',
      },
    };
  },
});

